package com.evernorth.smartemp.controller;
import com.evernorth.smartemp.repository.AuditLogRepository; import lombok.RequiredArgsConstructor; import org.springframework.http.*; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/admin/audit-logs") @RequiredArgsConstructor public class AuditLogController { private final AuditLogRepository repo;
 @GetMapping(produces="text/csv") public ResponseEntity<String> download(){StringBuilder b=new StringBuilder("id,action,username,details,createdAt\n");repo.findAllByOrderByCreatedAtDesc().forEach(x->b.append(x.getId()).append(',').append(csv(x.getAction())).append(',').append(csv(x.getUsername())).append(',').append(csv(x.getDetails())).append(',').append(x.getCreatedAt()).append('\n'));return ResponseEntity.ok().header(HttpHeaders.CONTENT_DISPOSITION,"attachment; filename=audit-logs.csv").body(b.toString());} private String csv(String s){return "\""+(s==null?"":s.replace("\"","\"\""))+"\"";}}
